    <script>
        function toggleBranch() {
            const card = document.getElementById('branchCard');
            card.classList.toggle('expanded');
        }

        async function selectBranch(option) {
            // 关键修改：先发送消息，再触发命令
            // 使用 /send 命令将选项内容作为用户消息发送
            await triggerSlashWithResult('/send ' + option);
            // 等待一小段时间确保消息发送完成
            await new Promise(resolve => setTimeout(resolve, 100));
            // 然后触发 /trigger 命令
            triggerSlash('/trigger');
        }

        const branchText = `$1`;
        const options = branchText.trim().split('\n').filter(line => line.trim());
        const optionsContainer = document.getElementById('branchOptions');

        options.forEach((option, index) => {
            const optionDiv = document.createElement('div');
            optionDiv.className = 'branch-option';
            optionDiv.innerHTML = `<span class="option-number">${index + 1}</span><span class="option-text">${option.trim()}</span>`;
            optionDiv.onclick = () => selectBranch(option.trim());
            optionsContainer.appendChild(optionDiv);
        });

        setTimeout(() => {
            document.getElementById('branchCard').classList.add('expanded');
        }, 100);
    </script>
